const settingsKey = 'settings';
let backgroundAudioControl = null;
let backgroundAudioSize = 0;
let backgroundAudioPath = '/static/audio/画音工作室-子鹤.mp3';

let audioContext = null;
let gainNode = null;
let mediaSource = null;

let settings = {
    backgroundAudio: 0, // 0 = 关闭, >0 = 开启，范围在0 ~ 1之间
    soundEffectAudio: 0, // 0 = 关闭, >0 = 开启，范围在0 ~ 1之间
    notificationAudio: 0, // 0 = 关闭, >0 = 开启，范围在0 ~ 1之间
    endpointAddress: '', // 端点地址
    endpointKey: '', // 端点密钥
    defaultModel: '' // 默认模型
}

document.addEventListener('DOMContentLoaded', async function () {
    await configToastr();
    await loadSettings();
});
document.addEventListener('click', async function () {
    await playBackgroundAudio();
});

async function configToastr() {
    toastr.options = {
        closeButton: false, // 是否显示关闭按钮
        debug: false, // 是否启用调试模式
        newestOnTop: false, // 新的消息是否显示在顶部
        progressBar: false, // 是否显示进度条
        positionClass: "toast-top-center", // 消息框在页面显示的位置
        preventDuplicates: false, // 是否防止重复消息出现
        onclick: null, // 消息框被点击时的回调函数
        showDuration: 300, // 显示动作持续时间
        hideDuration: 1000, // 隐藏动作持续时间
        timeOut: 2000, // 自动关闭超时时间
        extendedTimeOut: 1000, // 鼠标悬停时延长自动关闭的时间
        showEasing: "swing", // 显示动画的缓动方式
        hideEasing: "linear", // 隐藏动画的缓动方式
        showMethod: "fadeIn", // 显示动画方式
        hideMethod: "fadeOut" // 隐藏动画方式
    }
}

async function loadSettings() {
    try {
        const raw = localStorage.getItem(settingsKey);
        if (!raw) return;
        const loadedSettings = JSON.parse(raw);
        settings.backgroundAudio = loadedSettings.backgroundAudio || 0;
        settings.soundEffectAudio = loadedSettings.soundEffectAudio || 0;
        settings.notificationAudio = loadedSettings.notificationAudio || 0;
        settings.endpointAddress = loadedSettings.endpointAddress || 'https://mixed.strai.life';
        settings.endpointKey = loadedSettings.endpointKey || 'sk-HALdMZeiRaLWhv2HoRZ1dhAnMNrE7Svz0wWg7kkCsJbzJsn9';
        settings.defaultModel = loadedSettings.defaultModel || '[ais]gemini-3.5-flash';
        return true;
    } catch (error) {
        return false;
    }
}

async function saveSettings() {
    try {
        localStorage.setItem(settingsKey, JSON.stringify(settings));
        return true;
    } catch (error) {
        return false;
    }
}

async function setBackgroundAudioVolume(volume) {
    if (gainNode) {
        gainNode.gain.setValueAtTime(Math.max(0, Math.min(1, volume)), audioContext.currentTime);
    }
}

async function initWebAudio() {
    if (!audioContext) {
        audioContext = new (window.AudioContext || window.webkitAudioContext)();
    }
    if (audioContext.state === 'suspended') {
        audioContext.resume();
    }
    if (!gainNode) {
        gainNode = audioContext.createGain();
        gainNode.connect(audioContext.destination);
    }
}

async function playBackgroundAudio() {
    if (!backgroundAudioControl) {
        backgroundAudioControl = document.createElement('audio');
        backgroundAudioControl.id = 'background-audio';
        backgroundAudioControl.loop = true;
        backgroundAudioControl.preload = 'auto';
        backgroundAudioControl.setAttribute('playsinline', '');
        backgroundAudioControl.setAttribute('webkit-playsinline', '');
        backgroundAudioControl.crossOrigin = 'anonymous';
        backgroundAudioControl.src = encodeURI(backgroundAudioPath);
        document.body.appendChild(backgroundAudioControl);

        await initWebAudio();

        mediaSource = audioContext.createMediaElementSource(backgroundAudioControl);
        mediaSource.connect(gainNode);

        await setBackgroundAudioVolume(settings.backgroundAudio);
    }

    if (settings.backgroundAudio > 0) {
        await initWebAudio();
        await setBackgroundAudioVolume(settings.backgroundAudio);
        await backgroundAudioControl.play();
    } else {
        backgroundAudioControl.pause();
    }

}
